export const allProducts: Product[] = [
  ...recifeProducts,
  ...salvadorProducts,
  ...fortalezaProducts,
  ...saoluisProducts,
  ...natalProducts,
  ...maceioProducts,
];

export function getProductsByUnit(unitId: string): Product[] {
  return allProducts.filter((p) => p.unitId === unitId);
}

export function getProductById(unitId: string, productId: string): Product | undefined {
  return allProducts.find((p) => p.unitId === unitId && p.id === productId);
}